func Load(configPath string) (*Config, error) {
	cfg := &Config{
		BaseURL: "https://searchconsole.googleapis.com",
	}

	// Resolve config path
	path := configPath
	if path == "" {
		path = os.Getenv("GOOGLE_SEARCH_CONSOLE_CONFIG")
	}
	if path == "" {
		home, _ := os.UserHomeDir()
		path = filepath.Join(home, ".config", "google-search-console-pp-cli", "config.toml")
	}
	cfg.Path = path

	// PATCH(oauth-login): clean up stale .tmp files from interrupted writes.
	// If a process crashed between WriteFile(tmp) and Rename, a 0600-mode tmp
	// file containing tokens is left behind. Best-effort remove on every Load.
	_ = os.Remove(path + ".tmp")

	// Try to load config file
	data, err := os.ReadFile(path)
	if err == nil {
		if err := toml.Unmarshal(data, cfg); err != nil {
			return nil, fmt.Errorf("parsing config %s: %w", path, err)
		}
	}

	// Env var overrides
	if v := os.Getenv("GSC_ACCESS_TOKEN"); v != "" {
		cfg.AccessToken = v
		cfg.AuthSource = "env:GSC_ACCESS_TOKEN"
	}

	// Label config-file-derived credentials so doctor can distinguish
	// "credentials persisted on disk" from "no credentials at all" — without
	// this, users who saved via set-token without an env var see a blank
	// auth_source and can't tell whether their config is being picked up.
	// The label is the literal "config" rather than "config:<path>"; the
	// config file path is exposed separately as report["config_path"], and
	// embedding it in auth_source leaks the user's home directory through
	// doctor's JSON envelope.
	if cfg.AuthSource == "" && (cfg.AuthHeaderVal != "" || cfg.AccessToken != "") {
		cfg.AuthSource = "config"
	}

	// Base URL override (used by printing-press verify to point at mock/test servers)
	if v := os.Getenv("GOOGLE_SEARCH_CONSOLE_BASE_URL"); v != "" {
		cfg.BaseURL = v
	}
	return cfg, nil
}

// PATCH(oauth-login): the original second `if c.AccessToken != ""` branch was
// dead code (identical predicate to the first). Auth source is now resolved at
